// GET /v1/connected_apps/clients/{client_id}
package main

import (
	"context"
	"log"

	"github.com/stytchauth/stytch-go/v17/stytch/b2b/b2bstytchapi"
	"github.com/stytchauth/stytch-go/v17/stytch/consumer/connectedapps/clients"
)

func main() {
	client, err := b2bstytchapi.NewClient(
		"${projectId}",
		"${secret}",
	)
	if err != nil {
		log.Fatalf("error instantiating client: %v", err)
	}

	params := &clients.GetParams{
		ClientID: "${exampleConnectedAppClientID}",
	}

	resp, err := client.ConnectedApp.Clients.Get(context.Background(), params)
	if err != nil {
		log.Fatalf("error in method call: %v", err)
	}

	log.Println(resp)
}

