// GET /v1/b2b/sso/{organization_id}
package main

import (
	"context"
	"log"

	"github.com/stytchauth/stytch-go/v17/stytch/b2b/b2bstytchapi"
	"github.com/stytchauth/stytch-go/v17/stytch/b2b/sso"
	"github.com/stytchauth/stytch-go/v17/stytch/methodoptions"
)

func main() {
	client, err := b2bstytchapi.NewClient(
		"${projectId}",
		"${secret}",
	)
	if err != nil {
		log.Fatalf("error instantiating client: %v", err)
	}

	params := &sso.GetConnectionsParams{
		OrganizationID: "${organizationId}",
	}

	options := &sso.GetConnectionsParamsOptions{
		Authorization: methodoptions.Authorization{
			SessionToken: "${sessionToken}",
		},
	}

	resp, err := client.SSO.GetConnections(context.Background(), params, options)
	if err != nil {
		log.Fatalf("error in method call: %v", err)
	}

